SELECT e.ip_instance, COUNT(*) as num_events
FROM events e
GROUP BY e.ip_instance;

SELECT LTRIM(ip_instance) AS ip_instance, LTRIM(severity) AS severity, COUNT(*) AS event_count
FROM events
GROUP BY LTRIM(ip_instance), LTRIM(severity);

SELECT e.event_name, i.location, e.severity
FROM events e
JOIN ip_instances i ON e.ip_instance = i.instance_name;

SELECT i.instance_name, e.event_name
FROM ip_instances i
JOIN events e ON i.instance_name = e.ip_instance;

SELECT AVG(event_count) AS Average_Event_Count
FROM (
  SELECT user_id, COUNT(event_id) AS event_count
  FROM event_logs
  GROUP BY user_id
) AS event_counts;

SELECT COUNT(DISTINCT instance_name) 
FROM ip_instances 
WHERE status = 'Inactive';
